from firecrawl import FirecrawlApp

app = FirecrawlApp(api_key='fc-xxxxxxxxxxxxx')

# 爬取整個網站
crawl_result = app.crawl_url(
    'https://docs.anthropic.com',
    params={
        'limit': 100,             # 最多爬 100 頁
        'maxDepth': 3,           # 最深 3 層
        'allowBackwardLinks': False,
        'scrapeOptions': {
            'formats': ['markdown'],
            'onlyMainContent': True  # 只要主要內容，去掉 nav/footer
        }
    }
)

# 結果係所有頁面嘅 Markdown
for page in crawl_result['data']:
    print(f"URL: {page['url']}")
    print(f"內容長度: {len(page['markdown'])} 字符")
    print("---")

import FirecrawlApp from '@mendable/firecrawl-js';

const app = new FirecrawlApp({ apiKey: 'fc-xxxxx' });

// 爬取並提取
const result = await app.extract(
  ['https://news.ycombinator.com'],
  {
    prompt: '提取今日 Hacker News 頭條新聞標題、鏈接、評論數',
    schema: {
      type: 'object',
      properties: {
        stories: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              title: { type: 'string' },
              url: { type: 'string' },
              comments: { type: 'number' }
            }
          }
        }
      }
    }
  }
);

console.log(result.data.stories.slice(0, 5));
